// App.js
import React, { useEffect, useCallback } from 'react';
import { Linking, View, Text, StyleSheet, TouchableOpacity, Alert } from 'react-native';
import { NavigationContainer, useNavigation } from '@react-navigation/native';
import { createNativeStackNavigator } from '@react-navigation/native-stack';

const Stack = createNativeStackNavigator();

// Deep Link Configuration
const DEEP_LINK_PREFIX = 'myapp://';

const linking = {
  prefixes: [DEEP_LINK_PREFIX, 'https://myapp.com'],
  config: {
    screens: {
      Home: '',
      Profile: 'profile/:userId',
      PaymentConfirm: 'payment/confirm',
      PaymentDetails: 'payment/details/:transactionId',
      Campaign: 'campaign/:campaignId',
      Notification: 'notification/:notificationId',
      NotFound: '*',
    },
  },
};

// Deep Link Parser Utility
const parseDeepLink = (url) => {
  if (!url) return null;

  try {
    const cleanUrl = url.replace(DEEP_LINK_PREFIX, '').replace('https://myapp.com/', '');
    const [path, queryString] = cleanUrl.split('?');
    const segments = path.split('/').filter(Boolean);

    // Parse query parameters
    const params = {};
    if (queryString) {
      queryString.split('&').forEach((param) => {
        const [key, value] = param.split('=');
        params[decodeURIComponent(key)] = decodeURIComponent(value || '');
      });
    }

    // Route matching
    if (segments[0] === 'profile' && segments[1]) {
      return {
        screen: 'Profile',
        params: { userId: segments[1], ...params },
      };
    }

    if (segments[0] === 'payment' && segments[1] === 'confirm') {
      return {
        screen: 'PaymentConfirm',
        params: { ...params },
      };
    }

    if (segments[0] === 'payment' && segments[1] === 'details' && segments[2]) {
      return {
        screen: 'PaymentDetails',
        params: { transactionId: segments[2], ...params },
      };
    }

    if (segments[0] === 'campaign' && segments[1]) {
      return {
        screen: 'Campaign',
        params: { campaignId: segments[1], ...params },
      };
    }

    if (segments[0] === 'notification' && segments[1]) {
      return {
        screen: 'Notification',
        params: { notificationId: segments[1], ...params },
      };
    }

    return { screen: 'NotFound', params: { url } };
  } catch (error) {
    console.error('Error parsing deep link:', error);
    return null;
  }
};

// Deep Link Analytics Tracker
const trackDeepLinkEvent = (url, screen, params) => {
  console.log('[DeepLink Analytics]', {
    timestamp: new Date().toISOString(),
    url,
    screen,
    params,
    source: params?.utm_source || 'direct',
    medium: params?.utm_medium || 'unknown',
    campaign: params?.utm_campaign || 'none',
  });
  // In production, send to your analytics service
  // analytics.track('deep_link_opened', { url, screen, params });
};

// Custom Hook for Deep Link Handling
const useDeepLinkHandler = () => {
  const handleDeepLink = useCallback(({ url }) => {
    if (!url) return;

    console.log('[DeepLink] Received URL:', url);
    const parsed = parseDeepLink(url);

    if (parsed) {
      trackDeepLinkEvent(url, parsed.screen, parsed.params);
    }
  }, []);

  useEffect(() => {
    // Handle deep link when app is already open (foreground)
    const subscription = Linking.addEventListener('url', handleDeepLink);

    // Handle deep link when app is opened from closed state
    const getInitialURL = async () => {
      try {
        const initialUrl = await Linking.getInitialURL();
        if (initialUrl) {
          console.log('[DeepLink] Initial URL:', initialUrl);
          handleDeepLink({ url: initialUrl });
        }
      } catch (error) {
        console.error('[DeepLink] Error getting initial URL:', error);
      }
    };

    getInitialURL();

    return () => {
      subscription.remove();
    };
  }, [handleDeepLink]);
};

