// Home Screen
const HomeScreen = () => {
  const navigation = useNavigation();

  const testDeepLinks = [
    { label: 'Profile #123', url: 'myapp://profile/123' },
    { label: 'Profile with UTM', url: 'myapp://profile/456?utm_source=email&utm_campaign=summer_sale' },
    { label: 'Payment Confirm', url: 'myapp://payment/confirm?amount=99.99&currency=USD' },
    { label: 'Payment Details', url: 'myapp://payment/details/TXN-789' },
    { label: 'Campaign Promo', url: 'myapp://campaign/summer2024?discount=20&utm_source=push' },
    { label: 'Notification', url: 'myapp://notification/notif-001?type=order_update' },
    { label: 'Invalid Route', url: 'myapp://unknown/route' },
  ];

  const simulateDeepLink = async (url) => {
    console.log('[DeepLink] Simulating:', url);
    const parsed = parseDeepLink(url);
    if (parsed) {
      trackDeepLinkEvent(url, parsed.screen, parsed.params);
      navigation.navigate(parsed.screen, parsed.params);
    }
  };

  const openExternalDeepLink = async (url) => {
    try {
      const supported = await Linking.canOpenURL(url);
      if (supported) {
        await Linking.openURL(url);
      } else {
        Alert.alert('Error', `Cannot open URL: ${url}`);
      }
    } catch (error) {
      Alert.alert('Error', error.message);
    }
  };

  return (
    <View style={styles.container}>
      <Text style={styles.title}>🏠 Home Screen</Text>
      <Text style={styles.subtitle}>Deep Link Test Panel</Text>

      <View style={styles.buttonContainer}>
        {testDeepLinks.map((link, index) => (
          <TouchableOpacity
            key={index}
            style={styles.linkButton}
            onPress={() => simulateDeepLink(link.url)}
            onLongPress={() => openExternalDeepLink(link.url)}
          >
            <Text style={styles.linkButtonText}>{link.label}</Text>
            <Text style={styles.linkUrl}>{link.url}</Text>
          </TouchableOpacity>
        ))}
      </View>

      <Text style={styles.hint}>
        Tap to simulate deep link navigation.{'\n'}
        Long press to open via system Linking API.
      </Text>
    </View>
  );
};

