// ==================== PUSH NOTIFICATION DEEP LINK HANDLER ====================

// Utility to handle deep links from push notifications
// Call this from your push notification handler (e.g., Firebase, OneSignal)
export const handlePushNotificationDeepLink = (navigationRef, notificationData) => {
  if (!notificationData || !navigationRef?.current) return;

  const { deepLink, screen, params } = notificationData;

  if (deepLink) {
    // If the notification contains a full deep link URL
    const parsed = parseDeepLink(deepLink);
    if (parsed) {
      trackDeepLinkEvent(deepLink, parsed.screen, { ...parsed.params, source: 'push_notification' });
      navigationRef.current.navigate(parsed.screen, parsed.params);
    }
  } else if (screen) {
    // If the notification contains direct screen info
    trackDeepLinkEvent(`push://${screen}`, screen, { ...params, source: 'push_notification' });
    navigationRef.current.navigate(screen, params);
  }
};

// Marketing campaign deep link generator utility
export const generateDeepLink = (screen, params = {}, utmParams = {}) => {
  const screenPaths = {
    Profile: (p) => `profile/${p.userId}`,
    PaymentConfirm: () => 'payment/confirm',
    PaymentDetails: (p) => `payment/details/${p.transactionId}`,
    Campaign: (p) => `campaign/${p.campaignId}`,
    Notification: (p) => `notification/${p.notificationId}`,
  };

  const pathGenerator = screenPaths[screen];
  if (!pathGenerator) return null;

  const path = pathGenerator(params);
  const allParams = { ...params, ...utmParams };

  // Remove path params from query string
  const pathParamKeys = ['userId', 'transactionId', 'campaignId', 'notificationId'];
  const queryParams = Object.entries(allParams)
    .filter(([key]) => !pathParamKeys.includes(key))
    .map(([key, value]) => `${encodeURIComponent(key)}=${encodeURIComponent(value)}`)
    .join('&');

  const url = `myapp://${path}${queryParams ? `?${queryParams}` : ''}`;
  return url;
};

